using System.Collections.Concurrent;
using sv_6e4c2ed83ad94dd19e12dd17437f9e91.Models;

namespace sv_6e4c2ed83ad94dd19e12dd17437f9e91.Services;

/// <summary>
/// Singleton store for wizard data, keyed by ASP.NET Core session ID.
/// In per-page interactive server mode each navigation creates a new circuit,
/// so scoped services reset. This singleton survives across circuits while
/// the session-ID key keeps each user's data isolated.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        var data = _store.GetOrAdd(sessionId, _ => new WizardData());
        data.LastAccessed = DateTime.UtcNow;
        return data;
    }

    /// <summary>
    /// Remove entries older than the given threshold to prevent unbounded growth.
    /// Called from a hosted service or middleware if desired.
    /// </summary>
    public void Purge(TimeSpan maxAge)
    {
        var cutoff = DateTime.UtcNow - maxAge;
        foreach (var key in _store.Keys)
        {
            if (_store.TryGetValue(key, out var data) && data.LastAccessed < cutoff)
            {
                _store.TryRemove(key, out _);
            }
        }
    }
}

