using Microsoft.AspNetCore.Components;
using sv_6e4c2ed83ad94dd19e12dd17437f9e91.Models;
using sv_6e4c2ed83ad94dd19e12dd17437f9e91.Services;

namespace sv_6e4c2ed83ad94dd19e12dd17437f9e91.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles bridging the ASP.NET Core
/// session ID from the static-prerender phase into the interactive phase
/// via <see cref="PersistentComponentState"/>, then loads the shared
/// <see cref="WizardData"/> from the singleton <see cref="WizardStateStore"/>.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    [CascadingParameter] private HttpContext? HttpContext { get; set; }

    protected WizardData Data { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        string? sessionId = null;

        // During static prerender HttpContext is available.
        if (HttpContext is not null)
        {
            sessionId = HttpContext.Session.Id;
        }
        // During interactive phase, restore the session ID persisted during prerender.
        else if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var restored))
        {
            sessionId = restored;
        }

        if (!string.IsNullOrEmpty(sessionId))
        {
            _sessionId = sessionId;
            Data = Store.GetOrCreate(sessionId);
        }
    }

    private string _sessionId = "";

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    protected void SaveAndNavigate(int completedStep, string nextPath)
    {
        Data.CompletedSteps.Add(completedStep);
        Nav.NavigateTo(nextPath);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

