@page "/apply/experience"
@inherits WizardPageBase
@rendermode InteractiveServer
@using sv_6e4c2ed83ad94dd19e12dd17437f9e91.Models

<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (var i = 0; i < Data.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Job @(index + 1)</strong>
                <button type="button" class="btn btn-sm btn-outline-danger"
                        @onclick="() => RemoveJob(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="Data.JobHistory[index].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="Data.JobHistory[index].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="Data.JobHistory[index].Duration"
                       placeholder="e.g. Jan 2020 – Mar 2023" />
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddJob">
    + Add Job
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="Back">&laquo; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &raquo;</button>
</div>

@code {
    private void AddJob() => Data.JobHistory.Add(new JobEntry());
    private void RemoveJob(int index) => Data.JobHistory.RemoveAt(index);
    private void Back() => Nav.NavigateTo("/apply/personal-info");
    private void Next() => SaveAndNavigate(2, "/apply/references");
}

