    <dl class="row">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Data.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Data.Email</dd>
    </dl>
