    {
        @foreach (var job in Data.JobHistory)
        {
            <div class="card mb-2">
                <div class="card-body py-2">
                    <strong>@job.Title</strong> at @job.Company
                    <span class="text-muted ms-2">(@job.Duration)</span>
                </div>
            </div>
        }
    }
</section>

<section class="mb-4">
    <h4>References</h4>
    @if (Data.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        @foreach (var r in Data.References)
        {
            <div class="card mb-2">
                <div class="card-body py-2">
                    <strong>@r.Name</strong> — @r.Relationship
                    <span class="text-muted ms-2">(@r.Email)</span>
                </div>
            </div>
        }
