﻿@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_6e4c2ed83ad94dd19e12dd17437f9e91.Services.WizardStateStore Store

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        @if (_currentStep > 0)
        {
            <div class="top-row px-4 wizard-bar">
                <span class="me-3 fw-semibold">Step @_currentStep of 4</span>
                @foreach (var step in _steps)
                {
                    var isActive = step.Number == _currentStep;
                    var isComplete = _completedSteps.Contains(step.Number);
                    var css = isActive ? "btn btn-primary btn-sm me-1"
                            : isComplete ? "btn btn-outline-success btn-sm me-1"
                            : "btn btn-outline-secondary btn-sm me-1";
                    <a href="@step.Href" class="@css">
                        @if (isComplete && !isActive) { <span>✓ </span> }
                        @step.Label
                    </a>
                }
            </div>
        }
        else
        {
            <div class="top-row px-4">
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            </div>
        }

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter] private HttpContext? HttpContext { get; set; }

    private int _currentStep;
    private HashSet<int> _completedSteps = [];

    private static readonly (int Number, string Label, string Href)[] _steps =
    [
        (1, "Personal Info", "/apply/personal-info"),
        (2, "Experience",    "/apply/experience"),
        (3, "References",    "/apply/references"),
        (4, "Review",        "/apply/review"),
    ];

    protected override void OnInitialized()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/').ToLowerInvariant();
        _currentStep = path switch
        {
            "/apply/personal-info" => 1,
            "/apply/experience"    => 2,
            "/apply/references"    => 3,
            "/apply/review"        => 4,
            _ => 0,
        };

        // The layout renders statically, so HttpContext is always available here.
        if (_currentStep > 0 && HttpContext is not null)
        {
            _completedSteps = Store.GetOrCreate(HttpContext.Session.Id).CompletedSteps;
        }
    }
}

