+                @foreach (var step in _steps)
+                {
+                    var isActive = step.Number == _currentStep;
+                    var isComplete = _completedSteps.Contains(step.Number);
+                    var css = isActive ? "btn btn-primary btn-sm me-1"
+                            : isComplete ? "btn btn-outline-success btn-sm me-1"
+                            : "btn btn-outline-secondary btn-sm me-1";
+                    <a href="@step.Href" class="@css">
+                        @if (isComplete && !isActive) { <span>✓ </span> }
+                        @step.Label
+                    </a>
+                }
+            </div>
+        }
+        else
+        {
+            <div class="top-row px-4">
+                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
+            </div>
+        }

         <article class="content px-4">
             @Body
